private struct NetflixTabHost<Content: View>: View {
    let title: String
    let icon: String
    @ViewBuilder var content: () -> Content
    var body: some View { content() }
}

private enum NetflixScreenFactory {
    @ViewBuilder
    static func screen(for tab: String) -> some View {
        switch tab.lowercased() {
        case let t where t.contains("accueil") || t.contains("home") || t.contains("watch"):
            NetflixHomeScreen()
        case let t where t.contains("search") || t.contains("recherch") || t.contains("new") || t.contains("hot") || t.contains("short"):
            NetflixBrowseScreen()
        case let t where t.contains("profil") || t.contains("profile") || t.contains("netflix") || t.contains("watchlist") || t.contains("store") || t.contains("download") || t.contains("notif"):
            NetflixProfilePickerScreen()
        default:
            NetflixGenericListScreen(title: tab)
        }
    }
}
