private struct NetflixHomeScreen: View {
    var body: some View {
        NavigationStack {
            ZStack(alignment: .bottom) {
                ScrollView {
                    VStack(alignment: .leading, spacing: 20) {
                        NetflixHeroBillboard()
                        ForEach(NetflixDemoData.rows) { row in
                            NetflixPosterRow(title: row.title, items: row.items, accent: NetflixTokens.netflixRed)
                        }
                    }
                    .padding(.bottom, 24)
                }
                .background(NetflixTokens.netflixCanvas.ignoresSafeArea())
            }
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .principal) { Text("Netflix").font(.system(size: 20, weight: .bold)).foregroundStyle(NetflixTokens.netflixTextPrimary) }
                ToolbarItem(placement: .topBarTrailing) { Image(systemName: "person.crop.circle").foregroundStyle(NetflixTokens.netflixTextPrimary) }
            }
            .toolbarBackground(NetflixTokens.netflixCanvas, for: .navigationBar)
        }
    }
}

private struct NetflixHeroBillboard: View {
    var body: some View {
        ZStack(alignment: .bottomLeading) {
            RoundedRectangle(cornerRadius: 4).fill(
                LinearGradient(colors: [NetflixTokens.netflixSurface1, .black.opacity(0.3)], startPoint: .top, endPoint: .bottom)
            ).aspectRatio(16/9, contentMode: .fit)
            VStack(alignment: .leading, spacing: 8) {
                Text("SÉRIE TENDANCE").font(.system(size: 11, weight: .bold)).foregroundStyle(NetflixTokens.netflixTextSecondary)
                Text("L'Énigme de Belleville").font(.system(size: 28, weight: .bold)).foregroundStyle(.white)
                HStack(spacing: 12) {
                    Label("Lecture", systemImage: "play.fill").font(.system(size: 15, weight: .bold))
                        .frame(maxWidth: .infinity).padding(.vertical, 10)
                        .background(RoundedRectangle(cornerRadius: 4).fill(NetflixTokens.netflixRed))
                    Label("Plus d'infos", systemImage: "info.circle").font(.system(size: 15, weight: .semibold))
                        .frame(maxWidth: .infinity).padding(.vertical, 10)
                        .background(RoundedRectangle(cornerRadius: 4).fill(NetflixTokens.netflixSurface1))
                }
            }
            .padding(16)
        }
        .padding(.horizontal, 12)
    }
}

private struct NetflixPosterRow: View {
    let title: String; let items: [String]; let accent: Color
    var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            Text(title).font(.system(size: 17, weight: .bold)).foregroundStyle(.white).padding(.horizontal, 12)
            ScrollView(.horizontal, showsIndicators: false) {
                HStack(spacing: 8) {
                    ForEach(items, id: \.self) { item in
                        RoundedRectangle(cornerRadius: 4).fill(accent.opacity(0.35)).frame(width: 110, height: 160)
                            .overlay(alignment: .bottomLeading) {
                                Text(item).font(.system(size: 11, weight: .semibold)).foregroundStyle(.white).padding(6)
                            }
                    }
                }
                .padding(.horizontal, 12)
            }
        }
    }
}

