private struct NetflixProfilePickerScreen: View {
    let profiles = NetflixDemoData.profiles
    var body: some View {
        ZStack {
            NetflixTokens.netflixCanvas.ignoresSafeArea()
            VStack(spacing: 24) {
                Text("Qui regarde ?").font(.system(size: 32, weight: .bold)).foregroundStyle(NetflixTokens.netflixTextPrimary)
                HStack(spacing: 20) {
                    ForEach(profiles) { p in
                        VStack(spacing: 8) {
                            RoundedRectangle(cornerRadius: 4).fill(p.color).frame(width: 84, height: 84)
                                .overlay(Text(p.emoji).font(.system(size: 36)))
                            Text(p.name).foregroundStyle(NetflixTokens.netflixTextSecondary)
                        }
                    }
                    VStack(spacing: 8) {
                        RoundedRectangle(cornerRadius: 4).strokeBorder(NetflixTokens.netflixTextSecondary, lineWidth: 1).frame(width: 84, height: 84)
                            .overlay(Image(systemName: "plus").font(.title).foregroundStyle(NetflixTokens.netflixTextSecondary))
                        Text("Ajouter").foregroundStyle(NetflixTokens.netflixTextSecondary)
                    }
                }
            }
        }
    }
}

